#include <stdio.h>
#include <stdlib.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *arr = malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &arr[i]);
        int m = (N > 0) ? 1 : 0;
        for (int i = 1; i < N; ++i) {
            if (arr[i] != arr[i-1]) {
                arr[m++] = arr[i];
            }
        }
        printf("%d\n", m);
        for (int i = 0; i < m; ++i) {
            printf("%lld", arr[i]);
            if (i + 1 < m) printf(" ");
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

